using System;
using System.Runtime.InteropServices;

class Program
{
    [DllImport("user32.dll", CharSet = CharSet.Auto)]
    private static extern int MessageBox(IntPtr hWnd, string text, string caption, int options);

    static void Main(string[] args)
    {
        Console.WriteLine("P/Invoke ilə MessageBox çağırışı...");
        try
        {
            MessageBox(IntPtr.Zero, "Salam, dünya!", "P/Invoke Nümunəsi", 0);
            Console.WriteLine("MessageBox göstərildi.");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Səhv: {ex.Message}");
        }
    }
}
// Output (Windows-da):
// P/Invoke ilə MessageBox çağırışı...
// (Bir mesaj qutusu göstərilir)
// MessageBox göstərildi.
// Qeyd: Bu kod yalnız Windows-da işləyir. Pyodide-da dəstəklənmir.

using System;

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("Təhlükəli kod və göstəricilər...");
        int[] numbers = new[] { 10, 20, 30 };
        unsafe
        {
            fixed (int* ptr = numbers)
            {
                for (int i = 0; i < 3; i++)
                {
                    Console.WriteLine($"Dəyər: {*(ptr + i)}");
                }
            }
        }
    }
}
// Output:
// Təhlükəli kod və göstəricilər...
// Dəyər: 10
// Dəyər: 20
// Dəyər: 30

using System;

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("Təhlükəli kod səhvi...");
        int[] numbers = new[] { 1, 2, 3 };
        try
        {
            unsafe
            {
                fixed (int* ptr = numbers)
                {
                    Console.WriteLine($"Səhv ünvan: {*(ptr + 10)}");
                }
            }
        }
        catch (AccessViolationException ex)
        {
            Console.WriteLine("Səhv: Yaddaş ünvanına yanlış daxil olma!");
            Console.WriteLine($"Səhv mesajı: {ex.Message}");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Ümumi səhv: {ex.Message}");
        }
    }
}
// Output:
// Təhlükəli kod səhvi...
// Səhv: Yaddaş ünvanına yanlış daxil olma!
// Səhv mesajı: Attempted to read or write protected memory.

using System;

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("Səhvə yol açan göstəricil...");
        try
        {
            unsafe
            {
                int* ptr = null;
                *ptr = 42;
                Console.WriteLine($"Dəyər: {*ptr}");
            }
        }
        catch (NullReferenceException ex)
        {
            Console.WriteLine("Səhv: Null göstəriciyə daxil olma!");
            Console.WriteLine($"Səhv mesajı: {ex.Message}");
        }
    }
}
// Output:
// Səhvə yol açan göstəricil...
// Səhv: Null göstəriciyə daxil olma!
// Səhv mesajı: Object reference not set to an instance of an object.

